import React, { useState, useContext } from 'react';
import { AppContext } from '../context/AppContext';
import { useNavigate } from 'react-router-dom';

const LoginPage = () => {
  const [isReg, setIsReg] = useState(false);
  const [form, setForm] = useState({ username: '', password: '' });
  const { setUser } = useContext(AppContext);
  const navigate = useNavigate();

  const handleSubmit = async (e) => {
    e.preventDefault();
    const path = isReg ? '/register' : '/login';
    try {
      const res = await fetch(`http://localhost:3001${path}`, {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(form)
      });
      const data = await res.json();
      if (res.ok) {
        setUser(data);
        alert(isReg ? 'Регистрация успешна!' : 'С возвращением!');
        navigate('/');
      } else {
        alert(data.error || 'Ошибка доступа');
      }
    } catch (err) { alert('Сервер бэкенда не запущен!'); }
  };

  return (
    <div className="auth-box">
      <h2 style={{textAlign: 'center', marginBottom: '20px'}}>{isReg ? 'Создать аккаунт' : 'Авторизация'}</h2>
      <form onSubmit={handleSubmit}>
        <input type="text" placeholder="Логин" required onChange={e => setForm({...form, username: e.target.value})} />
        <input type="password" placeholder="Пароль" required onChange={e => setForm({...form, password: e.target.value})} />
        <button type="submit">{isReg ? 'Зарегистрироваться' : 'Войти'}</button>
      </form>
      <p onClick={() => setIsReg(!isReg)} style={{textAlign: 'center', marginTop: '20px', cursor: 'pointer', color: '#007bff'}}>
        {isReg ? 'Уже есть профиль? Войти' : 'Нет аккаунта? Регистрация'}
      </p>
    </div>
  );
};
export default LoginPage;
